import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjMessage } from "./OjMessage";
export { OjMessage };

/**
 * Create an instance of [[OjMessage]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojMessage(driver, By.id('my-oj-message'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojMessage(driver: DriverLike, by: By): Promise<OjMessage> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjMessage
  if (!(webEl instanceof OjMessage)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-message>`);
  }
  return webEl;
}

register("oj-message", OjMessage);
